const n = parseInt(process.argv[2]);
const parts = [];
for (let i = 0; i < n; i++)
    parts.push(String(i) + ' ');
const result = parts.join('');
let spaces = 0;
for (let i = 0; i < result.length; i++)
    if (result[i] === ' ') spaces++;
console.log(spaces);

const n = parseInt(process.argv[2]);
let text = [];
let pos = 0;
while (pos < n) {
    if (pos > 0 && pos % 1000 === 0 && pos + 5 <= n) {
        text.push('X','X','X','X','X');
        pos += 5;
    } else {
        text.push(String.fromCharCode(97 + pos % 5));
        pos++;
    }
}
const needle = "XXXXX";
let count = 0;
for (let i = 0; i <= text.length - 5; i++) {
    if (text[i]==='X' && text[i+1]==='X' && text[i+2]==='X' && text[i+3]==='X' && text[i+4]==='X') count++;
}
console.log(count);

const n = parseInt(process.argv[2]);
const arr = new Array(n);
let seed = 42;
for (let i = 0; i < n; i++) { seed=((Math.imul(seed,1103515245)+12345)>>>0)%2147483648; arr[i]=((seed>>16)&0x7fff)%n; }
const seen = new Set();
let count = 0;
for (const x of arr) { if (n-x>=0 && seen.has(n-x)) count++; seen.add(x); }
console.log(count);

const n = parseInt(process.argv[2]);
const map = new Map();
for (let i = 0; i < n; i++)
    map.set(i, i * 2);
let found = 0;
for (let i = 0; i < n; i++)
    if (map.get(i) === i * 2) found++;
console.log(found);

const n = parseInt(process.argv[2]);
const counts = new Array(1000).fill(0);
let seed = 42;
for (let i = 0; i < n; i++) {
    seed = ((Math.imul(seed, 1103515245) + 12345) >>> 0) % 2147483648;
    counts[((seed >> 16) & 0x7fff) % 1000]++;
}
let maxFreq = 0, maxIdx = 0, distinct = 0;
for (let i = 0; i < 1000; i++) {
    if (counts[i] > 0) distinct++;
    if (counts[i] > maxFreq) { maxFreq = counts[i]; maxIdx = i; }
}
console.log(`${maxFreq} ${maxIdx} ${distinct}`);

const n = parseInt(process.argv[2]);
let sum = 0;
for (let i = 1; i <= n; i++) {
    sum = (sum + i) % 1000000007;
}
console.log(sum);
